/* === 环形缓冲区架构定义 === */
#define RING_BUF_SIZE   256
#define RING_BUF_MASK   (RING_BUF_SIZE - 1)  /* 256 是 2 的幂，可用 & 替代 % */

typedef struct {
    volatile uint8_t buf[RING_BUF_SIZE];
    volatile uint32_t write_pos;  /* DMA 写入位置，硬件自动递增 */
    volatile uint32_t read_pos;   /* CPU 读取位置，软件维护 */
} dma_ring_buf_t;

static dma_ring_buf_t uart4_ring;
static uint8_t *dma_dest_addr;

void ring_buf_init(void) {
    /* 缓冲区清零 */
    memset(&uart4_ring, 0, sizeof(uart4_ring));
    /* DMA 目标地址设为缓冲区起始 */
    dma_dest_addr = uart4_ring.buf;
}

/* 返回缓冲区中可用数据的字节数 */
static inline uint32_t ring_buf_available(const dma_ring_buf_t *rb) {
    return rb->write_pos - rb->read_pos;
}

/* 从缓冲区读取一个字节，无数据时返回 0xFF 并设置 *has_data = false */
static inline uint8_t ring_buf_read(dma_ring_buf_t *rb, bool *has_data) {
    if (ring_buf_available(rb) == 0) {
        *has_data = false;
        return 0xFF;
    }
    *has_data = true;
    uint8_t byte = rb->buf[rb->read_pos & RING_BUF_MASK];
    rb->read_pos++;
    return byte;
}

/* === UART4 + DMA2 Stream5 循环接收初始化 === */
#define UART4_DMA_RX_BUF_SIZE  256

static uint8_t uart4_rx_buf[UART4_DMA_RX_BUF_SIZE];
static QueueHandle_t uart4_msg_queue;

void uart4_dma_init(QueueHandle_t msg_q) {
    uart4_msg_queue = msg_q;

    /* 启动 DMA 循环接收 —— 注意第三个参数是缓冲区大小 */
    /* HAL_UART_Receive_DMA() 内部会：
     * 1. 设置 DMA_SxPAR = &UART4->DR
     * 2. 设置 DMA_SxM0AR = uart4_rx_buf
     * 3. 设置 DMA_SxNDTR = UART4_DMA_RX_BUF_SIZE
     * 4. 设置 DMA_SxCR 的 CIRC=1 (循环), MINC=1 (内存增量), PINC=0 (外设不增量)
     * 5. 使能 DMA 传输完成中断
     */
    HAL_UART_Receive_DMA(&huart4, uart4_rx_buf, UART4_DMA_RX_BUF_SIZE);
}

/* === DMA 传输完成回调 —— 由 HAL 在中断上下文中调用 === */
void HAL_UARTEx_RxEventCallback(UART_HandleTypeDef *huart, uint16_t Size) {
    if (huart->Instance == UART4) {
        /* Size 参数告诉我们在本次传输周期中收到了多少字节
         * 在循环模式下，Size 通常是 UART4_DMA_RX_BUF_SIZE
         * 但如果中途触发了半传输中断，Size 可能是缓冲区的一半 */

        BaseType_t xHigherPriorityTaskWoken = pdFALSE;

        /* 将接收到的数据通过队列发送给处理任务
         * 这里使用指针传递而非拷贝，因为数据已经在缓冲区中 */
        uart4_rx_event_t evt = {
            .data = uart4_rx_buf,
            .len  = Size,
            .ts   = xTaskGetTickCount()
        };

        /* xQueueSendFromISR 是中断安全的 */
        xQueueSendFromISR(uart4_msg_queue, &evt, &xHigherPriorityTaskWoken);

        /* 触发上下文切换（如果有更高优先级任务因接收队列信号而就绪）*/
        portYIELD_FROM_ISR(xHigherPriorityTaskWoken);

        /* 重新启动 DMA 接收 —— 循环模式下这实际上是重新加载 NDTR 寄存器 */
        HAL_UART_Receive_DMA(&huart4, uart4_rx_buf, UART4_DMA_RX_BUF_SIZE);
    }
}

/* === 陷阱演示：数据竞争的撕裂读取 === */

/* ❌ 错误示范 —— 以 uint32_t 读取可能被 DMA 撕裂 */
void bad_word_read(dma_ring_buf_t *rb) {
    uint32_t value;
    /* 如果 DMA 正在写入这 4 个字节，value 可能是混合的 */
    memcpy(&value, &rb->buf[rb->read_pos & RING_BUF_MASK], 4);
    rb->read_pos += 4;
    process_value(value);  /* 处理撕裂后的错误值 */
}

/* ✅ 正确做法 1：逐字节读取（Cortex-M4 单字节原子操作）*/
void good_byte_read(dma_ring_buf_t *rb) {
    uint32_t value = 0;
    for (int i = 0; i < 4; i++) {
        value = (value << 8) | rb->buf[rb->read_pos & RING_BUF_MASK];
        rb->read_pos++;
    }
    process_value(value);  /* 每个字节读取都是原子的 */
}

/* ✅ 正确做法 2：双缓冲区 ping-pong 架构 */
#define DOUBLE_BUF_SIZE  256
static uint8_t ping_buf[DOUBLE_BUF_SIZE];
static uint8_t pong_buf[DOUBLE_BUF_SIZE];
static volatile int active_buf = 0;  /* 0=ping, 1=pong */

void DMA2_Stream5_IRQHandler(void) {
    if (DMA2->HISR & DMA_HISR_TCIF5) {
        /* DMA 完成了整个缓冲区的传输 */
        int completed = 1 - active_buf;  /* 刚完成的是 inactive 那个 */
        active_buf = completed;  /* 现在切换到另一个缓冲区 */

        /* 通知 CPU 处理 completed 缓冲区的数据 */
        BaseType_t xWake = pdFALSE;
        xQueueSendFromISR(process_queue, &completed, &xWake);
        portYIELD_FROM_ISR(xWake);
    }
}

/* === 重构前：轮询 UART 接收（散逸的特性 + 令人费解的流程）=== */
void main_loop(void) {
    while (1) {
        uint8_t rx_byte;
        /* 阻塞等待 —— CPU 在这里空转，什么也不做 */
        if (HAL_UART_Receive(&huart4, &rx_byte, 1, 10) == HAL_OK) {
            /* 收到一个字节，放入处理队列 */
            process_byte(rx_byte);
        }
        /* 如果 10ms 内没有数据，继续下一次循环 */
        /* 问题 1: 10ms 内到达的多个字节只会处理第一个 */
        /* 问题 2: CPU 在 HAL_UART_Receive 中完全空闲等待 */
        /* 问题 3: 如果数据以 115200bps 持续到达，每秒约 11500 次轮询 */
        vTaskDelay(pdMS_TO_TICKS(10));
    }
}

/* === 重构后：DMA 循环接收 + 事件驱动处理 === */

/* 第一步：定义环形缓冲区和管理结构 */
#define UART4_DMA_BUF_SIZE  512  /* 512 字节，2 的幂 */

typedef struct {
    uint8_t  buf[UART4_DMA_BUF_SIZE];
    uint32_t write_pos;  /* DMA 写入位置 */
    uint32_t read_pos;   /* CPU 读取位置 */
} uart4_ring_buf_t;

static uart4_ring_buf_t uart4_ring;
static QueueHandle_t uart4_evt_queue;

/* 第二步：初始化 —— 启动 DMA 循环接收 */
void uart4_init(void) {
    memset(&uart4_ring, 0, sizeof(uart4_ring));
    uart4_evt_queue = xQueueCreate(8, sizeof(uint16_t));  /* 事件队列，深度 8 */

    /* 启动 DMA 循环接收 —— 此后 DMA 自动将 UART 数据写入 uart4_ring.buf */
    HAL_UART_Receive_DMA(&huart4, uart4_ring.buf, UART4_DMA_BUF_SIZE);
}

/* 第三步：DMA 传输完成回调 —— 通知处理任务有新数据 */
void HAL_UARTEx_RxEventCallback(UART_HandleTypeDef *huart, uint16_t Size) {
    if (huart->Instance == UART4) {
        uart4_ring.write_pos += Size;
        BaseType_t xWake = pdFALSE;
        /* 发送事件给处理任务 —— 只传长度，不传数据指针 */
        xQueueSendFromISR(uart4_evt_queue, &Size, &xWake);
        portYIELD_FROM_ISR(xWake);
        /* 重新启动 DMA（循环模式下硬件会自动重载）*/
        HAL_UART_Receive_DMA(&huart4, uart4_ring.buf, UART4_DMA_BUF_SIZE);
    }
}

/* 第四步：数据处理任务 —— 从环形缓冲区提取有效数据 */
void uart4_process_task(void *pv) {
    uint16_t bytes_received;
    while (1) {
        /* 等待 DMA 回调发来的事件 */
        if (xQueueReceive(uart4_evt_queue, &bytes_received, portMAX_DELAY) == pdPASS) {
            /* 从环形缓冲区读取新数据 */
            uint32_t start = 0;  /* 记录上次读取位置用于调试 */
            for (uint16_t i = 0; i < bytes_received; i++) {
                uint32_t pos = uart4_ring.read_pos & (UART4_DMA_BUF_SIZE - 1);
                uint8_t byte = uart4_ring.buf[pos];
                uart4_ring.read_pos++;
                process_byte(byte);  /* 逐字节处理 */
            }
        }
    }
}
